{
  "name": "LegalLens Redline",
  "description": "A professional-grade text comparison tool for legal practitioners. Features smart redlining with blue additions, red deletions, and green move detection, powered by Gemini 2.5 for semantic analysis and risk assessment."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum ChangeType {
  UNCHANGED = 'UNCHANGED',
  ADDED = 'ADDED',
  REMOVED = 'REMOVED',
  MOVED = 'MOVED'
}

export interface DiffSegment {
  id: string;
  text: string;
  type: ChangeType;
  originalIndex?: number; // Where it came from if moved
}

export interface AnalysisResponse {
  summary: string;
  risks: string[];
  formattingIssues: string[];
}

export enum ViewMode {
  EDIT = 'EDIT',
  REDLINE = 'REDLINE'
}

import { GoogleGenAI, Type } from "@google/genai";

const apiKey = process.env.API_KEY || '';

// Initialize Gemini Client
// Note: We create a new instance per call in complex apps, but a singleton is fine here 
// as long as we handle the key correctly.
const getAIClient = () => new GoogleGenAI({ apiKey });

export const analyzeLegalDiff = async (original: string, modified: string) => {
  if (!original || !modified) return null;

  const ai = getAIClient();
  const prompt = `
    You are a senior legal associate. Compare the following "Original Clause" and "Modified Clause".

    Identify:
    1. The summary of legal impact of the changes.
    2. Potential risks introduced or removed.
    3. Any subtle wording changes that shift liability.

    Original Clause:
    "${original.substring(0, 5000)}"

    Modified Clause:
    "${modified.substring(0, 5000)}"
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash',
      contents: prompt,
      config: {
        systemInstruction: "You are a precise, risk-averse legal assistant. Output JSON.",
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            summary: { type: Type.STRING, description: "Executive summary of changes" },
            risks: { 
              type: Type.ARRAY, 
              items: { type: Type.STRING },
              description: "List of potential legal risks" 
            },
            formattingIssues: {
               type: Type.ARRAY,
               items: { type: Type.STRING },
               description: "Any potential formatting or reference errors"
            }
          }
        }
      }
    });

    return JSON.parse(response.text || '{}');
  } catch (error) {
    console.error("Gemini Analysis Error:", error);
    throw error;
  }
};

export const getDraftingSuggestion = async (text: string) => {
  const ai = getAIClient();
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash',
      contents: `Rewrite the following legal text to be more concise and neutral, while retaining its legal meaning:\n\n"${text}"`,
    });
    return response.text;
  } catch (error) {
    console.error("Gemini Drafting Error:", error);
    return null;
  }
};

import * as Diff from 'diff';
import { ChangeType, DiffSegment } from '../types';

export const generateSmartDiff = (original: string, modified: string): DiffSegment[] => {
  // 1. Calculate standard word-based diff
  const changes = Diff.diffWords(original, modified);

  // 2. Identify potential moves
  // Strategy: 
  // - Collect all REMOVED segments that are significant (e.g., > 10 chars)
  // - Check if an ADDED segment matches a REMOVED segment (fuzzy or exact)
  // - If match, mark ADDED as MOVED (Green).
  // - The REMOVED part in a "Redline" view is usually hidden if moved, or shown as struck-through with a note. 
  //   For this requested UI, we will mark the *destination* as Green (Move).

  const segments: DiffSegment[] = changes.map((change, index) => ({
    id: `seg-${index}`,
    text: change.value,
    type: change.added ? ChangeType.ADDED : change.removed ? ChangeType.REMOVED : ChangeType.UNCHANGED
  }));

  const removedSegments = segments.filter(s => s.type === ChangeType.REMOVED && s.text.trim().length > 10);
  const addedSegments = segments.filter(s => s.type === ChangeType.ADDED && s.text.trim().length > 10);

  addedSegments.forEach(added => {
    // Find a matching removed segment
    const matchIndex = removedSegments.findIndex(removed => {
      const cleanRemoved = removed.text.trim();
      const cleanAdded = added.text.trim();
      // Exact match for simplicity, or very close
      return cleanRemoved === cleanAdded;
    });

    if (matchIndex !== -1) {
      // Found a move!
      added.type = ChangeType.MOVED;

      // We also mark the source as 'Moved Out' ? 
      // In standard legal redline, often the deletion is still shown as struck, and insertion is double underlined.
      // But the user specifically asked for "Green Move".
      // We will leave the deletion as RED (Strike) and the addition as GREEN (Move) to visually indicate origin -> dest.
      // Optionally, we could hide the deletion if it's a move, but legal pros prefer seeing where it came from.

      // Let's remove the "removed" segment from the pool so it doesn't match twice
      removedSegments.splice(matchIndex, 1);
    }
  });

  return segments;
};

import React from 'react';

interface InputPanelProps {
  label: string;
  value: string;
  onChange: (val: string) => void;
  placeholder?: string;
  readOnly?: boolean;
}

const InputPanel: React.FC<InputPanelProps> = ({ label, value, onChange, placeholder, readOnly }) => {
  return (
    <div className="flex flex-col h-full bg-white rounded-lg shadow-sm border border-slate-200 overflow-hidden">
      <div className="px-4 py-3 bg-slate-50 border-b border-slate-200 flex justify-between items-center">
        <h3 className="font-semibold text-slate-700 text-sm uppercase tracking-wide">{label}</h3>
        <span className="text-xs text-slate-400 font-medium">{value.length} chars</span>
      </div>
      <textarea
        className="flex-1 p-4 resize-none focus:outline-none focus:ring-2 focus:ring-blue-500/20 legal-text text-slate-800 text-base"
        value={value}
        onChange={(e) => onChange(e.target.value)}
        placeholder={placeholder}
        readOnly={readOnly}
        spellCheck={false}
      />
    </div>
  );
};

export default InputPanel;

import React from 'react';
import { ChangeType, DiffSegment } from '../types';

interface RedlineViewerProps {
  segments: DiffSegment[];
}

const RedlineViewer: React.FC<RedlineViewerProps> = ({ segments }) => {
  // If no segments, show empty state
  if (segments.length === 0) {
    return (
      <div className="flex items-center justify-center h-full text-slate-400">
        <p>No changes detected or text is empty.</p>
      </div>
    );
  }

  return (
    <div className="legal-text text-base leading-relaxed whitespace-pre-wrap text-slate-800 bg-white p-8 min-h-full shadow-sm">
      {segments.map((segment) => {
        switch (segment.type) {
          case ChangeType.ADDED:
            return (
              <span 
                key={segment.id} 
                className="bg-blue-100 text-blue-700 underline decoration-blue-300 decoration-2 underline-offset-2 mx-0.5 rounded-sm px-0.5"
                title="Added"
              >
                {segment.text}
              </span>
            );
          case ChangeType.REMOVED:
            return (
              <span 
                key={segment.id} 
                className="bg-red-50 text-red-600 line-through decoration-red-400/50 decoration-2 mx-0.5 opacity-80"
                title="Deleted"
              >
                {segment.text}
              </span>
            );
          case ChangeType.MOVED:
            return (
              <span 
                key={segment.id} 
                className="bg-emerald-100 text-emerald-800 border-b-2 border-emerald-500 mx-0.5 px-0.5 rounded-sm font-medium"
                title="Moved Text"
              >
                {segment.text}
              </span>
            );
          case ChangeType.UNCHANGED:
          default:
            return <span key={segment.id}>{segment.text}</span>;
        }
      })}
    </div>
  );
};

export default RedlineViewer;

import React from 'react';
import { AnalysisResponse } from '../types';

