export default AnalysisSidebar;

import React, { useState, useEffect, useCallback } from 'react';
import { ViewMode, DiffSegment, AnalysisResponse } from './types';
import InputPanel from './components/InputPanel';
import RedlineViewer from './components/RedlineViewer';
import AnalysisSidebar from './components/AnalysisSidebar';
import { generateSmartDiff } from './utils/diffEngine';
import { analyzeLegalDiff } from './services/geminiService';

// Placeholder text for demo purposes
const DEMO_ORIGINAL = `1. Confidentiality.
The Receiving Party shall hold the Confidential Information in strict confidence and shall not disclose such information to any third party without the prior written consent of the Disclosing Party. The Receiving Party shall use the Confidential Information solely for the purpose of evaluating the Potential Transaction.

2. Term.
This Agreement shall remain in effect for a period of two (2) years from the Effective Date.`;

const DEMO_MODIFIED = `1. Confidentiality.
The Receiving Party shall hold the Confidential Information in reasonable confidence and shall not disclose such information to any third party (except to its affiliates and professional advisors) without the prior written consent of the Disclosing Party. The Receiving Party shall use the Confidential Information for any commercial purpose.

2. Term.
This Agreement shall remain in effect for a period of three (3) years from the Effective Date.

3. Governing Law.
This Agreement shall be governed by the laws of the State of New York.`;

const App: React.FC = () => {
  const [originalText, setOriginalText] = useState(DEMO_ORIGINAL);
  const [modifiedText, setModifiedText] = useState(DEMO_MODIFIED);
  const [viewMode, setViewMode] = useState<ViewMode>(ViewMode.EDIT);
  const [diffSegments, setDiffSegments] = useState<DiffSegment[]>([]);
  const [showAnalysis, setShowAnalysis] = useState(false);

  // AI State
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [analysisResult, setAnalysisResult] = useState<AnalysisResponse | null>(null);

  // Re-calculate diff whenever text changes
  useEffect(() => {
    const handler = setTimeout(() => {
      const segments = generateSmartDiff(originalText, modifiedText);
      setDiffSegments(segments);
    }, 300); // Debounce
    return () => clearTimeout(handler);
  }, [originalText, modifiedText]);

  const handleAnalyze = useCallback(async () => {
    if (!originalText || !modifiedText) return;

    setIsAnalyzing(true);
    setShowAnalysis(true); // Open sidebar
    try {
      const result = await analyzeLegalDiff(originalText, modifiedText);
      setAnalysisResult(result);
    } catch (err) {
      console.error(err);
      // In a real app, show toast error
    } finally {
      setIsAnalyzing(false);
    }
  }, [originalText, modifiedText]);

  return (
    <div className="flex flex-col h-screen overflow-hidden bg-slate-100">
      {/* Header */}
      <header className="h-16 bg-white border-b border-slate-200 flex items-center justify-between px-6 shrink-0 z-30 relative shadow-sm">
        <div className="flex items-center gap-3">
          <div className="bg-slate-900 text-white p-1.5 rounded-md">
            <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M3 6l3 1m0 0l-3 9a5.002 5.002 0 006.001 0M6 7l3 9M6 7l6-2m6 2l3-1m-3 1l-3 9a5.002 5.002 0 006.001 0M18 7l3 9m-3-9l-6-2m0-2v2m0 16V5m0 16H9m3 0h3" />
            </svg>
          </div>
          <h1 className="text-xl font-bold text-slate-800 tracking-tight">LegalLens <span className="text-slate-400 font-normal">Redline</span></h1>
        </div>

        <div className="flex items-center gap-2 bg-slate-100 p-1 rounded-lg border border-slate-200">
          <button
            onClick={() => setViewMode(ViewMode.EDIT)}
            className={`px-4 py-1.5 text-sm font-medium rounded-md transition-all ${
              viewMode === ViewMode.EDIT
                ? 'bg-white text-slate-900 shadow-sm'
                : 'text-slate-500 hover:text-slate-700'
            }`}
          >
            Edit & Compare
          </button>
          <button
            onClick={() => setViewMode(ViewMode.REDLINE)}
            className={`px-4 py-1.5 text-sm font-medium rounded-md transition-all ${
              viewMode === ViewMode.REDLINE
                ? 'bg-white text-slate-900 shadow-sm'
                : 'text-slate-500 hover:text-slate-700'
            }`}
          >
            Redline View
          </button>
        </div>

        <div className="flex items-center gap-3">
           <button
            onClick={() => setShowAnalysis(!showAnalysis)}
            className={`flex items-center gap-2 px-3 py-2 text-sm font-medium rounded-md transition-colors border ${
              showAnalysis 
                ? 'bg-purple-50 text-purple-700 border-purple-200' 
                : 'bg-white text-slate-700 border-slate-200 hover:bg-slate-50'
            }`}
          >
            <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
               <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19.428 15.428a2 2 0 00-1.022-.547l-2.384-.477a6 6 0 00-3.86.517l-.318.158a6 6 0 01-3.86.517L6.05 15.21a2 2 0 00-1.806.547M8 4h8l-1 1v5.172a2 2 0 00.586 1.414l5 5c1.26 1.26.367 3.414-1.415 3.414H4.828c-1.782 0-2.674-2.154-1.414-3.414l5-5A2 2 0 009 10.172V5L8 4z" />
            </svg>
            AI Assistant
          </button>
        </div>
      </header>

      {/* Main Content */}
      <main className="flex-1 flex overflow-hidden relative">
        <div className="flex-1 overflow-hidden p-6 transition-all duration-300">

          {viewMode === ViewMode.EDIT && (
            <div className="grid grid-cols-2 gap-6 h-full">
              <InputPanel 
                label="Original Document" 
                value={originalText} 
                onChange={setOriginalText} 
                placeholder="Paste original text here..."
              />
              <InputPanel 
                label="Modified Document" 
                value={modifiedText} 
                onChange={setModifiedText} 
                placeholder="Paste modified text here..."
              />
            </div>
          )}

          {viewMode === ViewMode.REDLINE && (
            <div className="h-full flex flex-col max-w-4xl mx-auto">
               <div className="bg-white rounded-t-lg border border-slate-200 border-b-0 p-4 flex justify-between items-center shadow-sm z-10">
                  <div className="flex gap-4 text-xs font-semibold uppercase tracking-wide">
                     <div className="flex items-center gap-1.5">
                        <span className="w-3 h-3 rounded-full bg-blue-100 border border-blue-400"></span>
                        <span className="text-slate-600">Added</span>
                     </div>
                     <div className="flex items-center gap-1.5">
                        <span className="w-3 h-3 rounded-full bg-red-100 border border-red-400 relative overflow-hidden">
                           <span className="absolute inset-0 border-t border-red-400 top-1/2 -rotate-45"></span>
                        </span>
                        <span className="text-slate-600">Deleted</span>
                     </div>
                     <div className="flex items-center gap-1.5">
                        <span className="w-3 h-3 rounded-full bg-emerald-100 border border-emerald-500"></span>
                        <span className="text-slate-600">Moved</span>
                     </div>
                  </div>
                  <button 
                    className="text-slate-400 hover:text-slate-600"
                    title="Export PDF (Demo)"
                  >
                     <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-4l-4 4m0 0l-4-4m4 4V4" />
                     </svg>
                  </button>
               </div>
               <div className="flex-1 overflow-y-auto bg-slate-50 border border-slate-200 rounded-b-lg shadow-sm">
                  <RedlineViewer segments={diffSegments} />
               </div>
            </div>
          )}
        </div>

        {/* AI Sidebar Overlay/Panel */}
        <div className={`transition-all duration-300 transform ${showAnalysis ? 'translate-x-0 w-80' : 'translate-x-full w-0 opacity-0'} absolute right-0 top-0 bottom-0 h-full`}>
           <AnalysisSidebar 
             isLoading={isAnalyzing} 
             analysis={analysisResult} 
             onAnalyze={handleAnalyze} 
           />
        </div>
      </main>
    </div>
  );
};

export default App;

export enum ChangeType {
  UNCHANGED = 'UNCHANGED',
  ADDED = 'ADDED',
  REMOVED = 'REMOVED',
  MOVED = 'MOVED'
}

export interface Document {
  id: string;
  name: string;
  text: string;
}

export interface DiffSegment {
  id: string;
  text: string;
  type: ChangeType;
  originalIndex?: number; // Where it came from if moved
}

export interface AnalysisResponse {
  summary: string;
  risks: string[];
  formattingIssues: string[];
}

export enum ViewMode {
  EDIT = 'EDIT', // Now the only mode, effectively
  REDLINE = 'REDLINE'
}

import React from 'react';
import { Document } from '../types';

interface InputPanelProps {
  label: string;
  roleDescription: string; // e.g., "Source" or "Target"
  selectedDocId: string;
  documents: Document[];
  onSelectDoc: (id: string) => void;
  onChangeText: (id: string, text: string) => void;
  onDeleteDoc?: (id: string) => void;
}

const InputPanel: React.FC<InputPanelProps> = ({ 
  label, 
  roleDescription,
  selectedDocId, 
  documents, 
  onSelectDoc, 
  onChangeText,
  onDeleteDoc 
}) => {
  const selectedDoc = documents.find(d => d.id === selectedDocId);

  return (
    <div className="flex flex-col h-full bg-white rounded-lg shadow-sm border border-slate-200 overflow-hidden">
      <div className="px-3 py-2 bg-slate-50 border-b border-slate-200 flex justify-between items-center gap-2">
        <div className="flex items-center gap-2 flex-1 overflow-hidden">
          <span className="text-xs font-bold text-slate-400 uppercase tracking-wider whitespace-nowrap">{roleDescription}</span>
          <select 
            className="flex-1 bg-white border border-slate-300 text-slate-800 text-sm rounded px-2 py-1 focus:outline-none focus:border-blue-500 cursor-pointer truncate"
            value={selectedDocId}
            onChange={(e) => onSelectDoc(e.target.value)}
          >
            {documents.map(doc => (
              <option key={doc.id} value={doc.id}>{doc.name}</option>
            ))}
          </select>
        </div>
        <div className="flex items-center gap-2">
           <span className="text-[10px] text-slate-400 font-medium tabular-nums">
             {selectedDoc?.text.length || 0} chars
           </span>
           {documents.length > 2 && onDeleteDoc && (
             <button 
               onClick={() => onDeleteDoc(selectedDocId)}
               className="text-slate-400 hover:text-red-500 transition-colors"
               title="Delete Document"
             >
               <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                 <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" />
               </svg>
             </button>
           )}
        </div>
      </div>
      <textarea
        className="flex-1 p-3 resize-none focus:outline-none focus:ring-2 focus:ring-blue-500/20 legal-text text-slate-700 text-sm leading-relaxed"
        value={selectedDoc?.text || ''}
        onChange={(e) => selectedDoc && onChangeText(selectedDoc.id, e.target.value)}
        placeholder="Select a document or paste text..."
        spellCheck={false}
      />
    </div>
  );
};

export default InputPanel;

import React from 'react';
import { ChangeType, DiffSegment } from '../types';

interface RedlineViewerProps {
  segments: DiffSegment[];
}

const RedlineViewer: React.FC<RedlineViewerProps> = ({ segments }) => {
  // If no segments, show empty state
  if (segments.length === 0) {
    return (
      <div className="flex items-center justify-center h-full text-slate-400 text-sm">
        <p>No changes detected or text is empty.</p>
      </div>
    );
  }

  return (
    <div className="legal-text text-sm leading-relaxed whitespace-pre-wrap text-slate-800 bg-white p-6 min-h-full shadow-sm">
      {segments.map((segment) => {
        switch (segment.type) {
          case ChangeType.ADDED:
            return (
              <span 
                key={segment.id} 
                className="bg-blue-100 text-blue-700 underline decoration-blue-300 decoration-2 underline-offset-2 mx-0.5 rounded-sm px-0.5"
                title="Added"
              >
                {segment.text}
              </span>
            );
          case ChangeType.REMOVED:
            return (
              <span 
                key={segment.id} 
                className="bg-red-50 text-red-600 line-through decoration-red-400/50 decoration-2 mx-0.5 opacity-80"
                title="Deleted"
              >
                {segment.text}
              </span>
            );
          case ChangeType.MOVED:
            return (
              <span 
                key={segment.id} 
                className="bg-emerald-100 text-emerald-800 border-b-2 border-emerald-500 mx-0.5 px-0.5 rounded-sm font-medium"
                title="Moved Text"
              >
                {segment.text}
              </span>
            );
          case ChangeType.UNCHANGED:
          default:
            return <span key={segment.id}>{segment.text}</span>;
        }
      })}
    </div>
  );
};

