interface InputPanelProps {
  label: string;
  roleDescription: string; // e.g., "Source" or "Target"
  selectedDocId: string;
  documents: Document[];
  onSelectDoc: (id: string) => void;
  onChangeText: (id: string, text: string) => void;
  onDeleteDoc?: (id: string) => void;
}

const InputPanel: React.FC<InputPanelProps> = ({ 
  label, 
  roleDescription,
  selectedDocId, 
  documents, 
  onSelectDoc, 
  onChangeText,
  onDeleteDoc 
}) => {
  const selectedDoc = documents.find(d => d.id === selectedDocId);

  return (
    <div className="flex flex-col h-full bg-white rounded-lg shadow-sm border border-slate-200 overflow-hidden">
      <div className="bg-slate-50 border-b border-slate-200 flex flex-col">
        {/* Header Label Row */}
        <div className="px-3 py-2 flex justify-between items-center">
             <div className="flex items-center gap-2">
                <span className="text-xs font-bold text-slate-500 uppercase tracking-wider">{label}</span>
                <span className="text-[10px] text-slate-400 font-medium px-1.5 py-0.5 rounded-full bg-slate-100 border border-slate-200">
                    {roleDescription}
                </span>
             </div>
             {documents.length > 2 && onDeleteDoc && (
                <button 
                  onClick={() => onDeleteDoc(selectedDocId)}
                  className="text-slate-400 hover:text-red-500 transition-colors"
                  title="Delete current document"
                >
                  <svg className="w-3.5 h-3.5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" />
                  </svg>
                </button>
             )}
        </div>

        {/* Tabs Row */}
        <div className="flex px-2 pb-2 gap-1 overflow-x-auto no-scrollbar">
            {documents.map(doc => {
                const isActive = doc.id === selectedDocId;
                return (
                    <button
                        key={doc.id}
                        onClick={() => onSelectDoc(doc.id)}
                        className={`
                            relative flex-1 min-w-[4rem] group flex items-center justify-center px-2 py-1.5 rounded-md border text-xs font-medium transition-all duration-200
                            ${isActive 
                                ? 'bg-white border-slate-300 text-slate-800 shadow-sm z-10' 
                                : 'bg-slate-100 border-transparent text-slate-500 hover:bg-slate-200 hover:text-slate-600'
                            }
                        `}
                        title={doc.name}
                    >
                        <span className="truncate max-w-[100px] block">{doc.name}</span>
                        {isActive && (
                            <span className="absolute -bottom-[9px] left-1/2 -translate-x-1/2 w-2 h-2 bg-white border-l border-b border-slate-200 rotate-45 z-20"></span>
                        )}
                    </button>
                )
            })}
        </div>
      </div>

      <textarea
        className="flex-1 p-3 resize-none focus:outline-none focus:ring-2 focus:ring-blue-500/20 legal-text text-slate-700 text-sm leading-relaxed"
        value={selectedDoc?.text || ''}
        onChange={(e) => selectedDoc && onChangeText(selectedDoc.id, e.target.value)}
        placeholder="Select a document or paste text..."
        spellCheck={false}
      />

       <div className="px-3 py-1 bg-white border-t border-slate-100 text-[10px] text-slate-400 text-right">
             {selectedDoc?.text.length || 0} characters
       </div>
    </div>
  );
};

