  onScroll?: (e: React.UIEvent<HTMLTextAreaElement>) => void;
}

const InputPanel: React.FC<InputPanelProps> = ({ 
  label, 
  roleDescription,
  selectedDocId, 
  documents, 
  onSelectDoc, 
  onChangeText,
  onRenameDoc,
  onDeleteDoc,
  scrollRef,
  onScroll
}) => {
  const selectedDoc = documents.find(d => d.id === selectedDocId);
  const [editingId, setEditingId] = useState<string | null>(null);
  const [tempName, setTempName] = useState('');

  const startEditing = (id: string, currentName: string) => {
    setEditingId(id);
    setTempName(currentName);
  };

  const finishEditing = () => {
    if (editingId && tempName.trim()) {
      onRenameDoc(editingId, tempName.trim());
    }
    setEditingId(null);
  };

  return (
    <div className="flex flex-col h-full bg-white rounded-lg shadow-sm border border-slate-200 overflow-hidden">
      <div className="bg-slate-50 border-b border-slate-200 flex flex-col">
        <div className="px-3 py-2 flex justify-between items-center">
             <div className="flex items-center gap-2">
                <span className="text-xs font-bold text-slate-500 uppercase tracking-wider">{label}</span>
                <span className="text-[10px] text-slate-400 font-medium px-1.5 py-0.5 rounded-full bg-slate-100 border border-slate-200">
                    {roleDescription}
                </span>
             </div>
             <div className="flex items-center gap-1">
                <button 
                  onClick={() => selectedDoc && onChangeText(selectedDoc.id, '')}
                  className="p-1 text-slate-400 hover:text-slate-600 transition-colors"
                  title="Clear Text"
                >
                  <svg className="w-3.5 h-3.5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" /></svg>
                </button>
                {documents.length > 2 && onDeleteDoc && (
                   <button 
                     onClick={() => onDeleteDoc(selectedDocId)}
                     className="p-1 text-slate-400 hover:text-red-500 transition-colors"
                     title="Delete document"
                   >
                     <svg className="w-3.5 h-3.5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" /></svg>
                   </button>
                )}
             </div>
        </div>

        <div className="flex px-2 pb-2 gap-1 overflow-x-auto no-scrollbar">
            {documents.map(doc => {
                const isActive = doc.id === selectedDocId;
                const isEditing = editingId === doc.id;

                return (
                    <div key={doc.id} className="relative flex-1 min-w-[5rem]">
                      {isEditing ? (
                        <input
                          autoFocus
                          className="w-full px-2 py-1.5 rounded-md border border-blue-400 text-xs font-medium focus:outline-none shadow-inner"
                          value={tempName}
                          onChange={(e) => setTempName(e.target.value)}
                          onBlur={finishEditing}
                          onKeyDown={(e) => e.key === 'Enter' && finishEditing()}
                        />
                      ) : (
                        <button
                          onClick={() => onSelectDoc(doc.id)}
                          onDoubleClick={() => startEditing(doc.id, doc.name)}
                          className={`
                              w-full group flex items-center justify-center px-2 py-1.5 rounded-md border text-xs font-medium transition-all duration-200
                              ${isActive 
                                  ? 'bg-white border-slate-300 text-slate-800 shadow-sm z-10' 
                                  : 'bg-slate-100 border-transparent text-slate-500 hover:bg-slate-200 hover:text-slate-600'
                              }
                          `}
                          title="Click to select, Double-click to rename"
                        >
                          <span className="truncate max-w-[80px] block">{doc.name}</span>
                          {isActive && (
                              <span className="absolute -bottom-[9px] left-1/2 -translate-x-1/2 w-2 h-2 bg-white border-l border-b border-slate-200 rotate-45 z-20"></span>
                          )}
                        </button>
                      )}
                    </div>
                )
            })}
        </div>
      </div>

      <textarea
        ref={scrollRef}
        onScroll={onScroll}
        className="flex-1 p-4 resize-none focus:outline-none focus:ring-2 focus:ring-blue-500/20 legal-text text-slate-700 text-sm leading-relaxed"
        value={selectedDoc?.text || ''}
        onChange={(e) => selectedDoc && onChangeText(selectedDoc.id, e.target.value)}
        placeholder="Select a document or paste text..."
        spellCheck={false}
      />

       <div className="px-3 py-1 bg-white border-t border-slate-100 text-[9px] text-slate-400 flex justify-between items-center">
             <span>{selectedDoc?.text.split(/\s+/).filter(x => x).length || 0} words</span>
             <span>{selectedDoc?.text.length || 0} chars</span>
       </div>
    </div>
  );
};

export default InputPanel;

import React from 'react';
import { ChangeType, DiffSegment } from '../types';

interface RedlineViewerProps {
  segments: DiffSegment[];
  scrollRef?: React.RefObject<HTMLDivElement | null>;
  onScroll?: (e: React.UIEvent<HTMLDivElement>) => void;
}

const RedlineViewer: React.FC<RedlineViewerProps> = ({ segments, scrollRef, onScroll }) => {
  const handleCopyRedline = () => {
    const text = segments.map(s => {
      if (s.type === ChangeType.ADDED) return `[+${s.text}+]`;
      if (s.type === ChangeType.REMOVED) return `[-${s.text}-]`;
      if (s.type === ChangeType.MOVED) return `[m>${s.text}<m]`;
      return s.text;
    }).join('');

    navigator.clipboard.writeText(text);
    alert('Redline copied to clipboard with markup markers.');
  };

  if (segments.length === 0) {
    return (
      <div className="flex items-center justify-center h-full text-slate-400 text-sm">
        <p>No changes detected.</p>
      </div>
    );
  }

  return (
    <div className="flex flex-col h-full bg-white relative">
      <div 
        ref={scrollRef}
        onScroll={onScroll}
        className="flex-1 legal-text text-sm leading-relaxed whitespace-pre-wrap text-slate-800 p-6 overflow-y-auto"
      >
        {segments.map((segment) => {
          switch (segment.type) {
            case ChangeType.ADDED:
              return (
                <span 
                  key={segment.id} 
                  className="bg-blue-100 text-blue-700 underline decoration-blue-300 decoration-2 underline-offset-2 mx-0.5 rounded-sm px-0.5"
                  id={segment.id}
                >
                  {segment.text}
                </span>
              );
            case ChangeType.REMOVED:
              return (
                <span 
                  key={segment.id} 
                  className="bg-red-50 text-red-600 line-through decoration-red-400/50 decoration-2 mx-0.5 opacity-80"
                  id={segment.id}
                >
                  {segment.text}
                </span>
              );
            case ChangeType.MOVED:
              return (
                <span 
                  key={segment.id} 
                  className="bg-emerald-100 text-emerald-800 border-b-2 border-emerald-500 mx-0.5 px-0.5 rounded-sm font-medium"
                  id={segment.id}
                >
                  {segment.text}
                </span>
              );
            case ChangeType.UNCHANGED:
            default:
              return <span key={segment.id}>{segment.text}</span>;
          }
        })}
      </div>

      <div className="absolute bottom-4 right-4 group">
        <button 
          onClick={handleCopyRedline}
          className="bg-slate-900 text-white p-2 rounded-full shadow-lg hover:scale-110 transition-transform flex items-center gap-2 px-4 text-xs font-bold"
        >
          <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M8 5H6a2 2 0 00-2 2v12a2 2 0 002 2h10a2 2 0 002-2v-1M8 5a2 2 0 002 2h2a2 2 0 002-2M8 5a2 2 0 012-2h2a2 2 0 012 2m-1 4h.01M9 16h5m0 0l-1.5 1.5M14 16l-1.5-1.5" /></svg>
          Copy Redline
        </button>
      </div>
    </div>
  );
};

export default RedlineViewer;

import React, { useState, useEffect, useCallback, useRef } from 'react';
import { Document, DiffSegment, AnalysisResponse, ChangeType } from './types';
import InputPanel from './components/InputPanel';
import RedlineViewer from './components/RedlineViewer';
import AnalysisSidebar from './components/AnalysisSidebar';
import { generateSmartDiff } from './utils/diffEngine';
import { analyzeLegalDiff } from './services/geminiService';

const DEMO_ORIGINAL = `1. Confidentiality.
The Receiving Party shall hold the Confidential Information in strict confidence and shall not disclose such information to any third party without the prior written consent of the Disclosing Party. The Receiving Party shall use the Confidential Information solely for the purpose of evaluating the Potential Transaction.

2. Term.
This Agreement shall remain in effect for a period of two (2) years from the Effective Date.`;

const DEMO_MODIFIED = `1. Confidentiality.
The Receiving Party shall hold the Confidential Information in reasonable confidence and shall not disclose such information to any third party (except to its affiliates and professional advisors) without the prior written consent of the Disclosing Party. The Receiving Party shall use the Confidential Information for any commercial purpose.

2. Term.
This Agreement shall remain in effect for a period of three (3) years from the Effective Date.

3. Governing Law.
This Agreement shall be governed by the laws of the State of New York.`;

const App: React.FC = () => {
  const [documents, setDocuments] = useState<Document[]>([
    { id: '1', name: 'Initial Draft', text: DEMO_ORIGINAL },
    { id: '2', name: 'Vendor Redline', text: DEMO_MODIFIED },
    { id: '3', name: 'Doc C', text: '' }
  ]);

  const [leftDocId, setLeftDocId] = useState('1');
  const [rightDocId, setRightDocId] = useState('2');
  const [diffSegments, setDiffSegments] = useState<DiffSegment[]>([]);
  const [showAnalysis, setShowAnalysis] = useState(false);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [analysisResult, setAnalysisResult] = useState<AnalysisResponse | null>(null);

  // Navigation State
  const [activeChangeIndex, setActiveChangeIndex] = useState(-1);

  // Sync Scroll Refs
  const leftRef = useRef<HTMLTextAreaElement>(null);
  const rightRef = useRef<HTMLTextAreaElement>(null);
  const redlineRef = useRef<HTMLDivElement>(null);
  const isSyncing = useRef(false);

  const leftDoc = documents.find(d => d.id === leftDocId) || documents[0];
  const rightDoc = documents.find(d => d.id === rightDocId) || documents[1] || documents[0];

  useEffect(() => {
    const handler = setTimeout(() => {
      if (leftDoc && rightDoc) {
        const segments = generateSmartDiff(leftDoc.text, rightDoc.text);
        setDiffSegments(segments);
        setActiveChangeIndex(-1);
      }
    }, 200);
    return () => clearTimeout(handler);
  }, [leftDoc, rightDoc]);

  // Synchronized Scrolling Logic
  const handleScroll = (e: React.UIEvent<HTMLElement>) => {
    if (isSyncing.current) return;
    isSyncing.current = true;
    const { scrollTop, scrollHeight, clientHeight } = e.currentTarget;
    const ratio = scrollTop / (scrollHeight - clientHeight);

    const targets = [leftRef.current, rightRef.current, redlineRef.current];
    targets.forEach(target => {
      if (target && target !== e.currentTarget) {
        target.scrollTop = ratio * (target.scrollHeight - target.clientHeight);
      }
    });

    setTimeout(() => { isSyncing.current = false; }, 50);
  };

  const handleUpdateText = (id: string, newText: string) => {
    setDocuments(prev => prev.map(doc => doc.id === id ? { ...doc, text: newText } : doc));
  };

  const handleRenameDoc = (id: string, newName: string) => {
    setDocuments(prev => prev.map(doc => doc.id === id ? { ...doc, name: newName } : doc));
  };

  const handleSwapPanels = () => {
    const temp = leftDocId;
    setLeftDocId(rightDocId);
    setRightDocId(temp);
  };

  const navigateChange = (direction: 'next' | 'prev') => {
    const changes = diffSegments.filter(s => s.type !== ChangeType.UNCHANGED);
    if (changes.length === 0) return;

    let nextIndex = direction === 'next' ? activeChangeIndex + 1 : activeChangeIndex - 1;
    if (nextIndex >= changes.length) nextIndex = 0;
    if (nextIndex < 0) nextIndex = changes.length - 1;

    setActiveChangeIndex(nextIndex);
    const element = document.getElementById(changes[nextIndex].id);
    if (element) {
      element.scrollIntoView({ behavior: 'smooth', block: 'center' });
      element.classList.add('ring-4', 'ring-blue-400', 'ring-opacity-50');
      setTimeout(() => element.classList.remove('ring-4', 'ring-blue-400', 'ring-opacity-50'), 2000);
    }
  };

  const handleAddDocument = () => {
    if (documents.length >= 4) return;
    const newId = Date.now().toString();
    const newDoc: Document = {
      id: newId,
      name: `Doc ${String.fromCharCode(65 + documents.length)}`,
      text: ''
    };
    setDocuments([...documents, newDoc]);
    setRightDocId(newId);
  };

  const handleDeleteDocument = (id: string) => {
    if (documents.length <= 2) return;
    const remaining = documents.filter(d => d.id !== id);
    setDocuments(remaining);
    if (leftDocId === id) setLeftDocId(remaining[0].id);
    if (rightDocId === id) setRightDocId(remaining[1]?.id || remaining[0].id);
  };

  const handleAnalyze = useCallback(async () => {
    if (!leftDoc || !rightDoc) return;
    setIsAnalyzing(true);
    setShowAnalysis(true);
    try {
      const result = await analyzeLegalDiff(leftDoc.text, rightDoc.text);
      setAnalysisResult(result);
    } catch (err) {
      console.error(err);
    } finally {
      setIsAnalyzing(false);
    }
  }, [leftDoc, rightDoc]);

  return (
    <div className="flex flex-col h-screen overflow-hidden bg-slate-100 font-sans">
      <header className="h-14 bg-white border-b border-slate-200 flex items-center justify-between px-4 shrink-0 z-30 relative shadow-sm">
        <div className="flex items-center gap-3">
          <div className="bg-slate-900 text-white p-1 rounded-md">
            <svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 12h6m-6 4h6m2 5H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2z" />
            </svg>
          </div>
          <h1 className="text-lg font-bold text-slate-800 tracking-tight">LegalLens <span className="text-slate-400 font-normal">Redline</span></h1>
        </div>

        <div className="flex items-center gap-4">
           <button
             onClick={handleSwapPanels}
             className="p-2 text-slate-500 hover:bg-slate-100 rounded-full transition-colors"
             title="Swap Source & Target"
           >
             <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M8 7h12m0 0l-4-4m4 4l-4 4m0 6H4m0 0l4 4m-4-4l4-4" /></svg>
           </button>
           <button
             onClick={handleAddDocument}
             disabled={documents.length >= 4}
             className={`flex items-center gap-1 px-3 py-1.5 text-xs font-semibold rounded border transition-colors ${
               documents.length >= 4 ? 'bg-slate-50 text-slate-300 border-slate-200' : 'bg-white text-blue-600 border-blue-200 hover:bg-blue-50'
             }`}
           >
             <svg className="w-3 h-3" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 4v16m8-8H4"/></svg>
             Add Doc
           </button>
        </div>

        <button
          onClick={() => setShowAnalysis(!showAnalysis)}
          className={`flex items-center gap-2 px-3 py-1.5 text-xs font-medium rounded-md transition-colors border ${
            showAnalysis ? 'bg-purple-50 text-purple-700 border-purple-200' : 'bg-white text-slate-700 border-slate-200 hover:bg-slate-50'
          }`}
        >
          <svg className="w-3.5 h-3.5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M13 10V3L4 14h7v7l9-11h-7z" /></svg>
          AI Assistant
        </button>
      </header>

      <main className="flex-1 flex overflow-hidden relative">
        <div className="flex-1 grid grid-cols-1 lg:grid-cols-3 gap-0 divide-x divide-slate-200 overflow-hidden">
          <div className="flex flex-col h-full overflow-hidden bg-slate-50/50 p-2">
             <InputPanel 
                label="Source" roleDescription="Original" selectedDocId={leftDocId} documents={documents}
                onSelectDoc={setLeftDocId} onChangeText={handleUpdateText} onRenameDoc={handleRenameDoc}
                onDeleteDoc={handleDeleteDocument} scrollRef={leftRef} onScroll={handleScroll}
             />
          </div>
          <div className="flex flex-col h-full overflow-hidden bg-slate-50/50 p-2">
             <InputPanel 
                label="Target" roleDescription="Modified" selectedDocId={rightDocId} documents={documents}
                onSelectDoc={setRightDocId} onChangeText={handleUpdateText} onRenameDoc={handleRenameDoc}
                onDeleteDoc={handleDeleteDocument} scrollRef={rightRef} onScroll={handleScroll}
             />
          </div>
          <div className="flex flex-col h-full overflow-hidden bg-white p-2 z-10">
             <div className="flex flex-col h-full bg-white rounded-lg shadow-sm border border-slate-200 overflow-hidden">
                <div className="px-3 py-2 bg-slate-50 border-b border-slate-200 flex justify-between items-center shrink-0">
                   <h3 className="font-semibold text-slate-700 text-xs uppercase tracking-wide">Redline Comparison</h3>
                   <div className="flex items-center gap-3">
                      <div className="flex gap-2 text-[10px] font-bold uppercase tracking-tight">
                         <div className="flex items-center gap-0.5"><span className="w-1.5 h-1.5 rounded-full bg-blue-400"></span><span className="text-slate-500">Add</span></div>
                         <div className="flex items-center gap-0.5"><span className="w-1.5 h-1.5 rounded-full bg-red-400"></span><span className="text-slate-500">Del</span></div>
                         <div className="flex items-center gap-0.5"><span className="w-1.5 h-1.5 rounded-full bg-emerald-500"></span><span className="text-slate-500">Move</span></div>
                      </div>
                      <div className="h-4 w-px bg-slate-300 mx-1"></div>
                      <div className="flex items-center gap-1">
                        <button onClick={() => navigateChange('prev')} className="p-1 hover:bg-slate-200 rounded text-slate-400 hover:text-slate-600"><svg className="w-3.5 h-3.5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M5 15l7-7 7 7" /></svg></button>
                        <span className="text-[10px] font-mono text-slate-400">{activeChangeIndex + 1}/{diffSegments.filter(s => s.type !== ChangeType.UNCHANGED).length}</span>
                        <button onClick={() => navigateChange('next')} className="p-1 hover:bg-slate-200 rounded text-slate-400 hover:text-slate-600"><svg className="w-3.5 h-3.5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 9l-7 7-7-7" /></svg></button>
                      </div>
                   </div>
                </div>
                <div className="flex-1 overflow-hidden">
                   <RedlineViewer segments={diffSegments} scrollRef={redlineRef} onScroll={handleScroll} />
                </div>
             </div>
          </div>
        </div>

        <div className={`transition-all duration-300 transform ${showAnalysis ? 'translate-x-0 w-80 shadow-2xl' : 'translate-x-full w-0 opacity-0'} absolute right-0 top-0 bottom-0 h-full bg-white border-l border-slate-200 z-50`}>
           <AnalysisSidebar isLoading={isAnalyzing} analysis={analysisResult} onAnalyze={handleAnalyze} />
        </div>
      </main>
    </div>
  );
};

export default App;

