               </button>
            )}
        </div>
      </div>

      <textarea
        ref={scrollRef}
        onScroll={onScroll}
        className="flex-1 p-4 resize-none focus:outline-none focus:ring-2 focus:ring-blue-500/20 legal-text text-slate-700 text-sm leading-relaxed"
