  const isSyncing = useRef(false);

  const leftDoc = documents.find(d => d.id === leftDocId) || documents[0];
  const rightDoc = documents.find(d => d.id === rightDocId) || documents[1] || documents[0];

  useEffect(() => {
    const handler = setTimeout(() => {
      if (leftDoc && rightDoc) {
        const segments = generateSmartDiff(leftDoc.text, rightDoc.text);
        setDiffSegments(segments);
        setActiveChangeIndex(-1);
      }
    }, 200);
    return () => clearTimeout(handler);
  }, [leftDoc, rightDoc]);

  // Synchronized Scrolling Logic
  const handleScroll = (e: React.UIEvent<HTMLElement>) => {
    if (isSyncing.current) return;
    isSyncing.current = true;
    const { scrollTop, scrollHeight, clientHeight } = e.currentTarget;
    const ratio = scrollTop / (scrollHeight - clientHeight);

    const targets = [leftRef.current, rightRef.current, redlineRef.current];
    targets.forEach(target => {
      if (target && target !== e.currentTarget) {
        target.scrollTop = ratio * (target.scrollHeight - target.clientHeight);
      }
    });

    setTimeout(() => { isSyncing.current = false; }, 50);
  };

  const handleUpdateText = (id: string, newText: string) => {
    setDocuments(prev => prev.map(doc => doc.id === id ? { ...doc, text: newText } : doc));
  };

  const handleRenameDoc = (id: string, newName: string) => {
    setDocuments(prev => prev.map(doc => doc.id === id ? { ...doc, name: newName } : doc));
  };

  const handleSwapPanels = () => {
    const temp = leftDocId;
    setLeftDocId(rightDocId);
    setRightDocId(temp);
  };

  const handleReset = () => {
    if (window.confirm('Are you sure you want to reset the workspace? This will clear all text and documents.')) {
      setDocuments([
        { id: '1', name: 'A', text: '' },
        { id: '2', name: 'B', text: '' }
      ]);
      setLeftDocId('1');
      setRightDocId('2');
      setActiveChangeIndex(-1);
    }
  };

  const navigateChange = (direction: 'next' | 'prev') => {
    const changes = diffSegments.filter(s => s.type !== ChangeType.UNCHANGED);
    if (changes.length === 0) return;

    let nextIndex = direction === 'next' ? activeChangeIndex + 1 : activeChangeIndex - 1;
    if (nextIndex >= changes.length) nextIndex = 0;
    if (nextIndex < 0) nextIndex = changes.length - 1;

    setActiveChangeIndex(nextIndex);
    const element = document.getElementById(changes[nextIndex].id);
    if (element) {
      element.scrollIntoView({ behavior: 'smooth', block: 'center' });
      element.classList.add('ring-4', 'ring-blue-400', 'ring-opacity-50');
      setTimeout(() => element.classList.remove('ring-4', 'ring-blue-400', 'ring-opacity-50'), 2000);
    }
  };

  const handleAddDocument = () => {
    if (documents.length >= 4) return;
    const newId = Date.now().toString();
    // Generate next letter: A, B, C, D based on length
    let nextChar = 65; // 'A'
    const existingNames = new Set(documents.map(d => d.name));
    while (existingNames.has(String.fromCharCode(nextChar)) && nextChar < 90) {
        nextChar++;
    }

    const newDoc: Document = {
      id: newId,
      name: String.fromCharCode(nextChar),
      text: ''
    };
    setDocuments([...documents, newDoc]);
    setRightDocId(newId);
  };

  const handleDeleteDocument = (id: string) => {
    if (documents.length <= 2) return;
    const remaining = documents.filter(d => d.id !== id);
    setDocuments(remaining);
    if (leftDocId === id) setLeftDocId(remaining[0].id);
    if (rightDocId === id) setRightDocId(remaining[1]?.id || remaining[0].id);
  };

  const changesCount = diffSegments.filter(s => s.type !== ChangeType.UNCHANGED).length;

  return (
    <div className="flex flex-col h-screen overflow-hidden bg-slate-50 font-sans">
      <header className="h-12 bg-white border-b border-slate-200 flex items-center justify-between px-4 shrink-0 shadow-sm z-10">
         <div className="flex items-center gap-2">
            <div className="w-6 h-6 bg-slate-800 rounded flex items-center justify-center text-white font-serif font-bold text-sm">L</div>
            <span className="font-bold text-slate-700">LegalLens</span>
         </div>
         <button 
           onClick={handleReset}
           className="text-xs font-medium text-slate-500 hover:text-red-600 transition-colors px-3 py-1.5 rounded hover:bg-red-50 flex items-center gap-1.5 border border-transparent hover:border-red-100"
           title="Clear all text and reset to default"
         >
            <svg className="w-3.5 h-3.5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" /></svg>
            Reset Workspace
         </button>
      </header>

      <main className="flex-1 flex overflow-hidden relative p-1">
        <div className="flex-1 grid grid-cols-1 lg:grid-cols-3 gap-1 overflow-hidden">

          {/* Column 1: Source */}
          <div className="flex flex-col h-full overflow-hidden">
             <InputPanel 
                label="Source" 
                roleDescription="Original" 
                selectedDocId={leftDocId} 
                documents={documents}
                onSelectDoc={setLeftDocId} 
                onChangeText={handleUpdateText} 
                onRenameDoc={handleRenameDoc}
                onDeleteDoc={handleDeleteDocument} 
                onAddDoc={handleAddDocument}
                scrollRef={leftRef} 
                onScroll={handleScroll}
             />
          </div>

          {/* Column 2: Target */}
          <div className="flex flex-col h-full overflow-hidden">
             <InputPanel 
                label="Target" 
                roleDescription="Modified" 
                selectedDocId={rightDocId} 
                documents={documents}
                onSelectDoc={setRightDocId} 
                onChangeText={handleUpdateText} 
                onRenameDoc={handleRenameDoc}
                onDeleteDoc={handleDeleteDocument} 
                onAddDoc={handleAddDocument}
                scrollRef={rightRef} 
                onScroll={handleScroll}
                headerAction={
                   <button
                     onClick={handleSwapPanels}
                     className="text-slate-400 hover:text-blue-600 transition-colors p-1 rounded hover:bg-slate-100"
                     title="Swap Source & Target"
                   >
                     <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M8 7h12m0 0l-4-4m4 4l-4 4m0 6H4m0 0l4 4m-4-4l4-4" /></svg>
                   </button>
                }
             />
          </div>

          {/* Column 3: Redline */}
          <div className="flex flex-col h-full overflow-hidden">
             <div className="flex flex-col h-full bg-white rounded-lg shadow-sm border border-slate-200 overflow-hidden">
                <div className="bg-slate-50 border-b border-slate-200 flex flex-col shrink-0">
                  <div className="px-3 py-2 flex justify-between items-center h-[38px]">
                     {/* Header Title & Legend */}
                     <div className="flex items-center gap-3">
                        <span className="text-xs font-bold text-slate-500 uppercase tracking-wider">Redline</span>
                        <div className="h-3 w-px bg-slate-300"></div>
                        <div className="flex gap-3 text-[10px] font-bold uppercase tracking-tight">
                           <div className="flex items-center gap-1"><span className="w-2 h-2 rounded-full bg-blue-500"></span><span className="text-slate-600">Add</span></div>
                           <div className="flex items-center gap-1"><span className="w-2 h-2 rounded-full bg-red-400"></span><span className="text-slate-600">Del</span></div>
                           <div className="flex items-center gap-1"><span className="w-2 h-2 rounded-full bg-emerald-500"></span><span className="text-slate-600">Move</span></div>
                        </div>
                     </div>

                     {/* Navigation Widget */}
                     <div className="flex items-center">
                        <div className="flex items-center bg-white border border-slate-200 rounded-md shadow-sm">
                          <button 
                            onClick={() => navigateChange('prev')} 
                            disabled={changesCount === 0}
                            className="p-1 hover:bg-slate-50 rounded-l-md text-slate-400 hover:text-slate-600 disabled:opacity-30"
                          >
                            <svg className="w-3.5 h-3.5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 19l-7-7 7-7" /></svg>
                          </button>

                          <div className="px-2 text-[10px] font-mono text-slate-500 font-medium min-w-[3rem] text-center border-x border-slate-100 h-full flex items-center justify-center">
