import React, { useState, useRef, useEffect } from 'react';
import { Document } from '../types';

interface InputPanelProps {
  label: string;
  roleDescription: string;
  selectedDocId: string;
  documents: Document[];
  onSelectDoc: (id: string) => void;
  onChangeText: (id: string, text: string) => void;
  onRenameDoc: (id: string, newName: string) => void;
  onDeleteDoc?: (id: string) => void;
  onAddDoc?: () => void;
  headerAction?: React.ReactNode;
  scrollRef?: React.RefObject<HTMLTextAreaElement | null>;
  onScroll?: (e: React.UIEvent<HTMLTextAreaElement>) => void;
}

const InputPanel: React.FC<InputPanelProps> = ({ 
  label, 
  roleDescription,
  selectedDocId, 
  documents, 
  onSelectDoc, 
  onChangeText,
  onRenameDoc,
  onDeleteDoc,
  onAddDoc,
  headerAction,
  scrollRef,
  onScroll
}) => {
  const selectedDoc = documents.find(d => d.id === selectedDocId);
  const [editingId, setEditingId] = useState<string | null>(null);
  const [tempName, setTempName] = useState('');

  const startEditing = (id: string, currentName: string) => {
    setEditingId(id);
    setTempName(currentName);
  };

  const finishEditing = () => {
    if (editingId && tempName.trim()) {
      onRenameDoc(editingId, tempName.trim());
    }
    setEditingId(null);
  };

  return (
    <div className="flex flex-col h-full bg-white rounded-lg shadow-sm border border-slate-200 overflow-hidden">
      <div className="bg-slate-50 border-b border-slate-200 flex flex-col">
        <div className="px-3 py-2 flex justify-between items-center">
             <div className="flex items-center gap-2">
                <span className="text-xs font-bold text-slate-500 uppercase tracking-wider">{label}</span>
                <span className="text-[10px] text-slate-400 font-medium px-1.5 py-0.5 rounded-full bg-slate-100 border border-slate-200">
                    {roleDescription}
                </span>
             </div>
             {headerAction && (
                <div className="flex items-center">
                  {headerAction}
                </div>
             )}
        </div>

        <div className="flex px-2 pb-2 gap-1 overflow-x-auto no-scrollbar items-center">
            {documents.map(doc => {
                const isActive = doc.id === selectedDocId;
                const isEditing = editingId === doc.id;

                return (
                    <div key={doc.id} className="relative flex-shrink-0 min-w-[4.5rem] max-w-[8rem] flex-1 group">
                      {isEditing ? (
                        <input
                          autoFocus
                          className="w-full px-2 py-1.5 rounded-md border border-blue-400 text-xs font-medium focus:outline-none shadow-inner"
                          value={tempName}
                          onChange={(e) => setTempName(e.target.value)}
                          onBlur={finishEditing}
                          onKeyDown={(e) => e.key === 'Enter' && finishEditing()}
                        />
                      ) : (
                        <button
                          onClick={() => onSelectDoc(doc.id)}
                          onDoubleClick={() => startEditing(doc.id, doc.name)}
                          className={`
                              w-full group flex items-center justify-center pl-2 pr-4 py-1.5 rounded-md border text-xs font-medium transition-all duration-200 relative
                              ${isActive 
                                  ? 'bg-white border-slate-300 text-slate-800 shadow-sm z-10' 
                                  : 'bg-slate-100 border-transparent text-slate-500 hover:bg-slate-200 hover:text-slate-600'
                              }
                          `}
                          title="Click to select, Double-click to rename"
                        >
                          <span className="truncate block">{doc.name}</span>
                          {isActive && (
                              <span className="absolute -bottom-[9px] left-1/2 -translate-x-1/2 w-2 h-2 bg-white border-l border-b border-slate-200 rotate-45 z-20"></span>
                          )}
                        </button>
                      )}

                      {/* Close Button - Top Right on Hover */}
                      {!isEditing && documents.length > 2 && onDeleteDoc && (
                        <button
                            onClick={(e) => {
                                e.stopPropagation();
                                onDeleteDoc(doc.id);
                            }}
                            className="absolute top-0.5 right-0.5 w-3.5 h-3.5 flex items-center justify-center rounded-full bg-white text-slate-400 border border-slate-200 hover:text-red-500 hover:border-red-300 opacity-0 group-hover:opacity-100 transition-all duration-200 z-30 shadow-sm hover:scale-110"
                            title="Close"
                        >
                            <svg className="w-2 h-2" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" /></svg>
                        </button>
                      )}
                    </div>
                )
            })}

            {onAddDoc && (
               <button
                 onClick={onAddDoc}
                 disabled={documents.length >= 4}
                 className={`
                    flex items-center justify-center w-7 h-7 rounded-md border text-xs transition-colors flex-shrink-0 ml-1
                    ${documents.length >= 4 
                       ? 'bg-slate-50 border-slate-200 text-slate-300 cursor-not-allowed' 
                       : 'bg-white border-slate-200 text-blue-500 hover:border-blue-300 hover:text-blue-600 shadow-sm'
                    }
                 `}
                 title="Add New Document"
               >
                 <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 4v16m8-8H4"/></svg>
               </button>
            )}
        </div>
      </div>

      <div className="relative flex-1 group">
        <textarea
          ref={scrollRef}
          onScroll={onScroll}
          className="w-full h-full p-4 resize-none focus:outline-none focus:ring-2 focus:ring-blue-500/20 legal-text text-slate-700 text-sm leading-relaxed"
          value={selectedDoc?.text || ''}
          onChange={(e) => selectedDoc && onChangeText(selectedDoc.id, e.target.value)}
          placeholder="Select a document or paste text..."
          spellCheck={false}
        />

        {/* Clear Text Button - Floating Top Right */}
        <button 
           onClick={() => selectedDoc && onChangeText(selectedDoc.id, '')}
           className="absolute top-2 right-2 p-1.5 bg-white/80 backdrop-blur-sm border border-slate-200 rounded-md text-slate-400 hover:text-red-500 hover:border-red-200 transition-all opacity-0 group-hover:opacity-100 shadow-sm"
           title="Clear Text"
         >
           <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" /></svg>
        </button>
      </div>

       <div className="px-3 py-1 bg-white border-t border-slate-100 text-[9px] text-slate-400 flex justify-between items-center">
             <span>{selectedDoc?.text.split(/\s+/).filter(x => x).length || 0} words</span>
             <span>{selectedDoc?.text.length || 0} chars</span>
       </div>
    </div>
  );
};

