                           title="Reset Workspace"
                       >
                           <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" /></svg>
                           <span className="text-[10px] font-bold uppercase tracking-wide hidden xl:inline">Reset</span>
                       </button>
                   </div>
                }
             />
          </div>

          {/* Column 3: Redline */}
          <div className="flex flex-col h-full overflow-hidden">
             <div className="flex flex-col h-full bg-white rounded-lg shadow-sm border border-slate-200 overflow-hidden">
                <div className="bg-slate-50 border-b border-slate-200 flex flex-col shrink-0">
                  <div className="px-3 py-2 flex justify-between items-center h-[38px]">
                     {/* Header Title & Legend */}
                     <div className="flex items-center gap-3">
                        <span className="text-xs font-bold text-slate-500 uppercase tracking-wider">Redline</span>
                        <div className="h-3 w-px bg-slate-300"></div>
                        <div className="flex gap-3 text-[10px] font-bold uppercase tracking-tight">
                           <div className="flex items-center gap-1"><span className="w-2 h-2 rounded-full bg-blue-500"></span><span className="text-slate-600">Add</span></div>
                           <div className="flex items-center gap-1"><span className="w-2 h-2 rounded-full bg-red-400"></span><span className="text-slate-600">Del</span></div>
                           <div className="flex items-center gap-1"><span className="w-2 h-2 rounded-full bg-emerald-500"></span><span className="text-slate-600">Move</span></div>
                        </div>
                     </div>

                     {/* Navigation Widget */}
                     <div className="flex items-center">
                        <div className="flex items-center bg-white border border-slate-200 rounded-md shadow-sm">
                          <button 
                            onClick={() => navigateChange('prev')} 
                            disabled={changesCount === 0}
                            className="p-1 hover:bg-slate-50 rounded-l-md text-slate-400 hover:text-slate-600 disabled:opacity-30"
                          >
                            <svg className="w-3.5 h-3.5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 19l-7-7 7-7" /></svg>
                          </button>

                          <div className="px-2 text-[10px] font-mono text-slate-500 font-medium min-w-[3rem] text-center border-x border-slate-100 h-full flex items-center justify-center">
                             {changesCount > 0 ? activeChangeIndex + 1 : 0} / {changesCount}
                          </div>

                          <button 
                            onClick={() => navigateChange('next')} 
                            disabled={changesCount === 0}
                            className="p-1 hover:bg-slate-50 rounded-r-md text-slate-400 hover:text-slate-600 disabled:opacity-30"
                          >
                            <svg className="w-3.5 h-3.5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 5l7 7-7 7" /></svg>
                          </button>
                        </div>
                     </div>
                  </div>

                  {/* Empty Spacer to match Tab height roughly */}
                  <div className="h-[36px] bg-white border-b border-slate-100 w-full flex items-center px-3">
                     <span className="text-[10px] text-slate-300 italic">
                        {changesCount === 0 ? 'No changes found' : `${changesCount} modifications detected`}
                     </span>
                  </div>
                </div>

                <div className="flex-1 overflow-hidden">
                   <RedlineViewer segments={diffSegments} scrollRef={redlineRef} onScroll={handleScroll} />
                </div>
             </div>
          </div>
        </div>
      </main>
    </div>
  );
};

export default App;
